StopScatterBingoAnimation(positions: number[]) : void {
    if (positions.length === 0) {
        return;
    }

    for (const position of positions) {
        const {col, row} = Common.GetColRowFromPosition(position);
        this.CleanSymbolAnim(col, row, Game_Define.LAYERS.PRIATE);
    }
}
//#endregion Scatter

/** 大獎預告表演 */
async PlayBigAwardEffect()
{
    this.m_aimSpine.node.parent.active = true;
    AudioManager.Play( AudioManager.AudioClips.MG_omen_prepare );
    await SpineKit.PlayAnimation( this.m_aimSpine, "Trans2_Start" );
    AudioManager.Play( AudioManager.AudioClips.MG_omen );
    // 震動
    let time = this.m_aimSpine.findAnimation( "Trans2" ).duration;
    this.m_gameView.BigHintShake( time );
    await SpineKit.PlayAnimation( this.m_aimSpine, "Trans2" );
    this.m_aimSpine.node.parent.active = false;
    this.m_gameView.RemoveBigHintShake();
}

